  KEY `idx_current_holder` (`current_holder_type`,`current_holder_id`),
  KEY `idx_source_warehouse_id` (`source_warehouse_id`),
  CONSTRAINT `assets_ibfk_1` FOREIGN KEY (`product_id`) REFERENCES `products` (`id`),
